import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  MenuItem,
  TextField,
  CircularProgress,
  Divider,
} from '@mui/material';
import { API_URL } from '../utils/apiUrl';
import { AuthContext } from '../context/AuthContext';

export default function SalesReport() {
  const { user } = useContext(AuthContext);
  const [outlets, setOutlets] = useState([]); // Admin er jonno outlet list
  const [selectedOutlet, setSelectedOutlet] = useState(
    user?.role === 'ADMIN' ? 'all' : user?.outlet_id
  );
  const [reportData, setReportData] = useState({
    totalRevenue: 0,
    topItems: [],
    recentSales: [],
  });
  const [loading, setLoading] = useState(true);

  // 1. Admin hole shob outlet fetch kora
  useEffect(() => {
    if (user?.role === 'ADMIN') {
      axios
        .get(`${API_URL}/api/outlets`)
        .then((res) => setOutlets(res.data.data || []));
    }
  }, [user]);

  // 2. Report Fetch (selectedOutlet change holei call hobe)
  const fetchReport = async () => {
    try {
      setLoading(true);
      const url = `${API_URL}/api/sales/report?outlet_id=${selectedOutlet}`;
      const response = await axios.get(url);
      setReportData(response.data);
    } catch (error) {
      console.error('Report Error:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (selectedOutlet) fetchReport();
  }, [selectedOutlet]);

  return (
    <Box sx={{ p: 3 }}>
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          mb: 3,
        }}
      >
        <Typography variant="h4" fontWeight="bold">
          {user?.role === 'ADMIN'
            ? 'HQ Global Sales Report'
            : `Sales Report - ${user?.outlet?.name}`}
        </Typography>

        {/* 3. Admin Dropdown (Specific outlet filter korar jonno) */}
        {user?.role === 'ADMIN' && (
          <TextField
            select
            label="Filter by Outlet"
            value={selectedOutlet}
            onChange={(e) => setSelectedOutlet(e.target.value)}
            sx={{ minWidth: 200 }}
          >
            <MenuItem value="all">All Outlets</MenuItem>
            {outlets.map((o) => (
              <MenuItem key={o.id} value={o.id}>
                {o.name}
              </MenuItem>
            ))}
          </TextField>
        )}
      </Box>

      {loading ? (
        <CircularProgress />
      ) : (
        <>
          <Grid container spacing={3} sx={{ mb: 4 }}>
            <Grid item xs={12} md={4}>
              <Card sx={{ bgcolor: 'success.main', color: 'white' }}>
                <CardContent>
                  <Typography variant="h6">Total Revenue</Typography>
                  <Typography variant="h3">
                    ৳{reportData.totalRevenue}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>

            <Grid item xs={12} md={8}>
              <Card variant="outlined">
                <CardContent>
                  <Typography variant="h6" fontWeight="bold">
                    Top 5 Selling Items
                  </Typography>
                  <Table size="small">
                    <TableHead>
                      <TableRow>
                        <TableCell>Product</TableCell>
                        <TableCell align="right">Qty</TableCell>
                        <TableCell align="right">Revenue</TableCell>
                      </TableRow>
                    </TableHead>
                    <TableBody>
                      {reportData.topItems.map((item, i) => (
                        <TableRow key={i}>
                          <TableCell>{item.name}</TableCell>
                          <TableCell align="right">{item.total_qty}</TableCell>
                          <TableCell align="right">
                            ৳{item.total_revenue}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </CardContent>
              </Card>
            </Grid>
          </Grid>

          <Card variant="outlined">
            <CardContent>
              <Typography variant="h6" fontWeight="bold" gutterBottom>
                Recent Sales
              </Typography>
              <Table>
                <TableHead sx={{ bgcolor: '#f5f5f5' }}>
                  <TableRow>
                    <TableCell>Receipt</TableCell>
                    <TableCell>Outlet</TableCell>
                    <TableCell>Customer</TableCell>
                    <TableCell>Amount</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {reportData.recentSales.map((sale) => (
                    <TableRow key={sale.id}>
                      <TableCell>
                        <b>{sale.receipt_no}</b>
                      </TableCell>
                      <TableCell>{sale.outlet?.name}</TableCell>
                      <TableCell>{sale.customer?.name || 'Guest'}</TableCell>
                      <TableCell>৳{sale.total_amount}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </>
      )}
    </Box>
  );
}
